 3	import { I18nNamespace } from '@config/config';
 4	import { Wizard, WizardHeader, WizardStep } from '@patternfly/react-core';
 5	import { useTranslation } from 'react-i18next';
 6	
 7	import { FormProvider } from './context/LinkFormProvider';
 8	import { Footer } from './Footer';
 9	import { FormPage } from './FormPage';
10	import { HowToPage } from './HowToPage';
