12	
13	// memo is used to prevent the component from being re-created when the Links Page updates data from the watcher
14	const LinkForm: FC<{ onSubmit: () => void; onCancel: () => void; siteId: string }> = memo(({ onSubmit, onCancel }) => {
15	  const { t } = useTranslation(I18nNamespace);
16	
17	  const CreateLinkWizard = function () {
18	    return (
19	      <FormProvider>
20	        <Wizard
21	          header={
22	            <WizardHeader
23	              title={t('Create link')}
24	              description={t('Links enable communication between sites. Once sites are linked, they form a network.')}
25	              isCloseHidden={true}
26	            />
27	          }
28	          footer={<Footer onCancel={onCancel} onSubmit={onSubmit} />}
29	        >
30	          <WizardStep name={t('How-To')} id="1-step" key="1-step">
31	            <HowToPage />
32	          </WizardStep>
33	
34	          <WizardStep name={t('Create a connection')} id="2-step" key="2-step">
35	            <FormPage />
36	          </WizardStep>
37	
38	          <WizardStep name={t('Summary')} id="3-step" key="3-step">
39	            <SummaryPage />
40	          </WizardStep>
41	        </Wizard>
42	      </FormProvider>
43	    );
44	  };
45	
46	  return <CreateLinkWizard />;
47	});
48	
